def send_post():
    try:
        # اختيار عشوائي من القائمة لضمان التنوع وعدم الفشل
        content = random.choice(messages)
        
        # إرسال المحتوى مع التذيل
        bot.send_message(CHANNEL_ID, content + F)
        print("Success! Post sent to channel.")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    send_post()
